def load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def env_default(name: str, default: Optional[str] = None) -> Optional[str]:
    v = os.environ.get(name)
    return v if v is not None and v != "" else default


def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser(description="Configure RabbitMQ vhosts, users, and permissions via Management HTTP API.")
    p.add_argument("--api-url", default=env_default("RABBITMQ_API_URL", "http://localhost:15672"), help="Base URL, e.g. http://host:15672")
    p.add_argument("--admin-user", default=env_default("RABBITMQ_ADMIN_USER", "guest"))
    p.add_argument("--admin-password", default=env_default("RABBITMQ_ADMIN_PASSWORD", "guest"))
    p.add_argument("--insecure", action="store_true", help="Disable TLS verification")
    p.add_argument("--timeout", type=int, default=int(env_default("RABBITMQ_API_TIMEOUT", "15")))
    p.add_argument("--retries", type=int, default=int(env_default("RABBITMQ_API_RETRIES", "5")))
    p.add_argument("--config", required=True, help="Path to JSON config file")
    p.add_argument("--dry-run", action="store_true", help="Validate config and print planned actions only")
