        if "vhost_limits" in t:
            admin.ensure_vhost_limits(ts.vhost, t["vhost_limits"])

        if "user_limits" in t:
            admin.ensure_user_limits(ts.user, t["user_limits"])

        if "policies" in t:
            admin.ensure_policies(ts.vhost, t["policies"])


